## MINIX 4 Slice 2.4 Reference: Run Queues, Timers, & Interrupt Dispatch

This document excerpts and annotates MINIX 3 scheduler, timer, and ARM architecture code to guide Slice 2.4 implementation (GICv3 + ARM generic timer + run queues, with two EL0 stub tasks proving preemption).

### 1. Run Queue & Scheduling (MINIX 3 model)

**Headers:** `/Users/kevinbarnard/src/learn/minix/minix/kernel/proc.h:141–174`

```c
/* Bits for the runtime flags. A process is runnable iff p_rts_flags == 0. */
#define RTS_SLOT_FREE   0x01
#define RTS_PROC_STOP   0x02
#define RTS_SENDING     0x04  /* blocked trying to send */
#define RTS_RECEIVING   0x08  /* blocked trying to receive */
#define RTS_SIGNALED    0x10
#define RTS_SIG_PENDING 0x20
#define RTS_P_STOP      0x40
#define RTS_NO_PRIV     0x80
#define RTS_NO_ENDPOINT 0x100
#define RTS_VMINHIBIT   0x200
#define RTS_PAGEFAULT   0x400
#define RTS_VMREQUEST   0x800
#define RTS_VMREQTARGET 0x1000
#define RTS_PREEMPTED   0x4000  /* preempted by higher priority; re-enqueue at head */
#define RTS_NO_QUANTUM  0x8000  /* ran out of quantum; dequeue then re-enqueue at tail */
#define RTS_BOOTINHIBIT 0x10000

/* A process is runnable iff p_rts_flags == 0. */
#define rts_f_is_runnable(flg) ((flg) == 0)
```

**Key insight:** A process is runnable **only if `p_rts_flags == 0`** (all flags clear). Setting any flag dequeues the process immediately (via `RTS_SET` macro). Clearing flags (via `RTS_UNSET`) re-enqueues if the process becomes fully runnable.

**Process table:** `/Users/kevinbarnard/src/learn/minix/minix/kernel/proc.h:22–65`

```c
struct proc {
  struct stackframe_s p_reg;    /* saved registers */
  proc_nr_t p_nr;
  volatile u32_t p_rts_flags;
  volatile u32_t p_misc_flags;
  char p_priority;              /* 0 = highest; NR_SCHED_QUEUES–1 = lowest */
  u64_t p_cpu_time_left;        /* quantum in CPU cycles */
  struct proc *p_nextready;     /* linked list within priority queue */
  ...
};
```

For Slice 2.4, implement a simplified `Proc` with `p_priority`, `p_cpu_time_left`, `p_nextready`.

#### Enqueue / Dequeue / Pick

**`enqueue()`:** `/Users/kevinbarnard/src/learn/minix/minix/kernel/proc.c:1605–1669`

```c
void enqueue(register struct proc *rp)
{
  int q = rp->p_priority;           /* priority = queue index */
  struct proc **rdy_head, **rdy_tail;

  assert(proc_is_runnable(rp));     /* Must be runnable before enqueue */

  rdy_head = get_cpu_var(rp->p_cpu, run_q_head);
  rdy_tail = get_cpu_var(rp->p_cpu, run_q_tail);

  /* Append to tail of queue q */
  if (!rdy_head[q]) {               /* queue empty */
    rdy_head[q] = rdy_tail[q] = rp;
    rp->p_nextready = NULL;
  } else {                          /* append */
    rdy_tail[q]->p_nextready = rp;
    rdy_tail[q] = rp;
    rp->p_nextready = NULL;
  }

  /* If enqueued process has higher priority than current, preempt */
  if (cpuid == rp->p_cpu) {
    struct proc *p = get_cpulocal_var(proc_ptr);
    if ((p->p_priority > rp->p_priority) &&
        (priv(p)->s_flags & PREEMPTIBLE))
      RTS_SET(p, RTS_PREEMPTED);    /* dequeues p, marks for re-enqueue at head */
  }
}
```

**For Slice 2.4:** Implement as two EL0 stubs with same priority; rely on `pick_proc()` round-robin within the priority queue. Preemption logic not needed until they differ in priority or block/unblock dynamically.

**`dequeue()`:** `/Users/kevinbarnard/src/learn/minix/minix/kernel/proc.c:1726–1790`

```c
void dequeue(struct proc *rp)
{
  int q = rp->p_priority;
  struct proc **xpp, *prev_xp;
  struct proc **rdy_tail;

  assert(!proc_is_runnable(rp));   /* Must not be runnable */

  rdy_tail = get_cpu_var(rp->p_cpu, run_q_tail);

  /* Unlink from queue */
  prev_xp = NULL;
  for (xpp = get_cpu_var_ptr(rp->p_cpu, run_q_head[q]); *xpp;
       xpp = &(*xpp)->p_nextready) {
    if (*xpp == rp) {
      *xpp = (*xpp)->p_nextready;   /* splice out */
      if (rp == rdy_tail[q])
        rdy_tail[q] = prev_xp;      /* update tail if needed */
      break;
    }
    prev_xp = *xpp;
  }

  rp->p_dequeued = get_monotonic();
}
```

**`pick_proc()`:** `/Users/kevinbarnard/src/learn/minix/minix/kernel/proc.c:1795–1823`

```c
static struct proc *pick_proc(void)
{
  register struct proc *rp;
  struct proc **rdy_head;
  int q;

  rdy_head = get_cpulocal_var(run_q_head);

  /* Scan priority queues 0, 1, 2, ... for first non-empty queue */
  for (q = 0; q < NR_SCHED_QUEUES; q++) {
    if (!(rp = rdy_head[q])) {
      TRACE(VF_PICKPROC, printf("queue %d empty\n", q););
      continue;
    }
    assert(proc_is_runnable(rp));
    if (priv(rp)->s_flags & BILLABLE)
      get_cpulocal_var(bill_ptr) = rp;
    return rp;  /* Return head of first non-empty queue */
  }
  return NULL;  /* No runnable processes */
}
```

**For Slice 2.4:** With two EL0 stubs at same priority, `pick_proc()` will return them FIFO. Implement run queues as a simple array: `run_q_head[NR_SCHED_QUEUES]`, `run_q_tail[NR_SCHED_QUEUES]`.

#### Quantum Exhaustion

**`proc_no_time()`:** `/Users/kevinbarnard/src/learn/minix/minix/kernel/proc.c:1903–1920`

```c
void proc_no_time(struct proc *p)
{
  if (!proc_kernel_scheduler(p) && priv(p)->s_flags & PREEMPTIBLE) {
    /* For preemptible user processes: notify their scheduler (dequeue + message) */
    notify_scheduler(p);
  } else {
    /* For kernel tasks: just renew quantum */
    p->p_cpu_time_left = ms_2_cpu_time(p->p_quantum_size_ms);
  }
}
```

**For Slice 2.4:** On each timer tick, decrement `p->p_cpu_time_left`. When it reaches 0, set `RTS_NO_QUANTUM` flag. In `switch_to_user()`, check this flag and reset the quantum before scheduling the next process.

---

### 2. Timer Interrupt & Quantum Management

**Clock handler:** `/Users/kevinbarnard/src/learn/minix/minix/kernel/clock.c:70–173`

```c
int timer_int_handler(void)
{
  /* Called on every tick (e.g., 100 Hz = 10 ms per tick) */

  struct proc *p, *billp;

  if (cpu_is_bsp(cpuid)) {
    kclockinfo.uptime++;
    /* real-time adjustments ... */
  }

  /* Update user/system accounting times */
  p = get_cpulocal_var(proc_ptr);        /* Current running process */
  billp = get_cpulocal_var(bill_ptr);    /* Billable process (for non-billable kernel tasks) */

  p->p_user_time++;                      /* Increment tick counter */
  if (!(priv(p)->s_flags & BILLABLE)) {
    billp->p_sys_time++;                 /* Charge system time to the billable process */
  }

  /* Decrement virtual timers (SIGVTALRM, SIGPROF) if active */
  if ((p->p_misc_flags & MF_VIRT_TIMER) && (p->p_virt_left > 0))
    p->p_virt_left--;
  if ((p->p_misc_flags & MF_PROF_TIMER) && (p->p_prof_left > 0))
    p->p_prof_left--;

  /* Check if any virtual timer expired; send SIGVTALRM/SIGPROF if needed */
  vtimer_check(p);
  if (p != billp)
    vtimer_check(billp);

  /* Update load average */
  load_update();

  /* Check if any system timers (e.g., alarm timers) have expired */
  if (clock_timers != NULL && tmr_has_expired(clock_timers, kclockinfo.uptime))
    tmrs_exptimers(&clock_timers, kclockinfo.uptime, NULL);

  /* Call arch-specific timer handler (e.g., to arm next interrupt) */
  arch_timer_int_handler();

  return 1;  /* Re-enable interrupts */
}
```

**For Slice 2.4:** Simplify to:
1. Increment a global `ticks` counter.
2. Decrement the current process's `p_cpu_time_left`.
3. If it reaches 0, set `RTS_NO_QUANTUM` and return to `switch_to_user()` via the exception path, which will pick a new process.

No need for virtual timers, load average, or accounting in Slice 2.4.

---

### 3. ARM (aarch64) Architecture in MINIX 3

**Does MINIX 3 support ARM?** Yes. MINIX 3 has `minix/kernel/arch/earm/` (ARM EABI) for older boards (BeagleBone Black, BeagleBone xM). However, **it does not include GICv3 or QEMU virt support**—it uses OMAP timers and legacy interrupt controllers.

**For Slice 2.4, we invent from scratch:** GICv3 is modern (ARMv8+); QEMU virt uses GICv3 by design.

---

### 4. ARM Exception Entry (aarch64 from MINIX 3 ARM port)

**IRQ entry path:** `/Users/kevinbarnard/src/learn/minix/minix/kernel/arch/earm/mpx.S:131–168`

```asm
ENTRY(irq_entry)
  switch_to_svc 4              /* Adjust LR by 4, save LR+SPSR to kernel stack */
  test_int_in_kernel irq_entry_from_kernel

irq_entry_from_user:
  save_process_ctx             /* Save user r0-r14, PC, PSR to proc.p_reg */

  ldr fp, [sp]                 /* fp = proc_ptr (saved on stack) */
  push {fp}
  sub sp, sp, #4               /* Align stack */

  mov r0, fp                   /* First param: caller proc_ptr */
  mov fp, #0                   /* Clear FP for stack trace */
  bl _C_LABEL(context_stop)    /* Account CPU time */

  bl _C_LABEL(bsp_irq_handle)  /* Dispatch IRQ (board-specific) */

  add sp, sp, #4
  pop {fp}
  dsb                          /* Data synchronization barrier */
  b _C_LABEL(switch_to_user)   /* Never returns; schedules next process */

irq_entry_from_kernel:
  push {r0-r12, lr}
  bl _C_LABEL(context_stop_idle)
  bl _C_LABEL(bsp_irq_handle)
  dsb
  pop {r0-r12, lr}
  rfeia sp!                    /* Return from exception with interrupt re-enable */
```

**Key:** After handling the IRQ, control always goes to `switch_to_user()` for user-mode interrupts, or `rfeia` for kernel-mode interrupts.

---

### 5. x86_64 Interrupt Dispatch (reference pattern)

**hwint_master macro:** `/Users/kevinbarnard/src/learn/minix/minix/kernel/arch/x86_64/mpx.S:103–123`

```asm
#define hwint_master(irq) \
  TEST_INT_IN_KERNEL(8, 0f)              /* Jump to label 0 if in kernel */ \
  \
  SAVE_PROCESS_CTX(0, KTS_INT_HARD)      /* Save user registers to proc table */ \
  movq %rbp, %rdi                        /* Pass proc_ptr to context_stop */ \
  xorq %rbp, %rbp                        /* Clear RBP for stack trace */ \
  call _C_LABEL(context_stop)            /* Account CPU time */ \
  PIC_IRQ_HANDLER(irq)                   /* Call irq_handle(irq) */ \
  movb $END_OF_INT, %al                  /* ACK PIC */ \
  outb $INT_CTL                          \
  jmp _C_LABEL(switch_to_user)           /* Schedule next process (never returns) */ \
  \
0:  /* nested interrupt (in kernel) */   \
  PUSHGPRS                               /* Save GPRs */ \
  call _C_LABEL(context_stop_idle)       /* Account idle time */ \
  PIC_IRQ_HANDLER(irq)                   /* Call irq_handle(irq) */ \
  movb $END_OF_INT, %al                  /* ACK PIC */ \
  outb $INT_CTL                          \
  CLEAR_IF(NESTED_RFLAGS_OFFSET(%rsp))   /* Clear IF in saved RFLAGS */ \
  POPGPRS                                /* Restore GPRs */ \
  iretq                                  /* Return from interrupt */
```

**Pattern:** User interrupt → save state → account time → dispatch handler → `switch_to_user()` (not `iretq`) to allow scheduler to pick a different process (preemption). Kernel interrupt → save minimal state → dispatch → `iretq` to return to kernel code.

---

### 6. GICv3 + ARM Generic Timer (minimal QEMU virt setup for Slice 2.4)

**No MINIX 3 reference exists** for GICv3 (it predates QEMU virt support in MINIX 3). This is a greenfield task.

**QEMU virt (`-M virt -cpu cortex-a72`) memory map:**

| Device | Base Address | Size | Notes |
|--------|--------------|------|-------|
| GIC Distributor (GICD) | 0x0800_0000 | 64 KB | Controls all interrupts |
| GIC Redistributor (GICR) | 0x0801_0000 | 64 KB × #CPUs | Per-CPU interrupt config |
| ARM Generic Timer CNTRL | 0x0901_0000 | 4 KB | Shared counter (read-only) |
| UART (PL011) | 0x0900_0000 | 4 KB | Serial I/O |

**Interrupt mapping (QEMU virt):**
- IRQ 27 = Virtual timer (CNTV) — PPI (Private Peripheral Interrupt)
- IRQs 32+ = SPI (Shared Peripheral Interrupt)

#### GICv3 Initialization (pseudocode for Slice 2.4)

```rust
// Enable GIC Distributor
gicd.ctrl = 0x1;  // EnableGrp0

// Enable GIC Redistributor for this CPU
gicr.ctrl |= 0x1;  // RWP_WAIT until done

// Configure virtual timer PPI as Group 1, non-secure
gicd.ppi_cfg[27] = 0x04000000;  // Group 1, level-triggered
gicd.priority[27] = 0x80;        // Priority 0x80 (mid-range)
gicd.enable[27] = 0x1;           // Enable interrupt

// Enable Group 1 interrupts at CPU interface
ICC_PMR_EL1 = 0xFF;              // Allow all priorities
ICC_IGRPEN1_EL1 |= 0x1;          // Enable Group 1
```

#### ARM Generic Timer Setup (CNTV — virtual timer)

```rust
// Arm virtual timer for ~10 ms (100 Hz tick)
CNTV_TVAL_EL0 = 0x100000;        // Load count-down value
CNTV_CTL_EL0 = 0x1;              // Enable (bit 0 = ENABLE)

// On each timer interrupt:
// 1. Read CNTV_CT_EL0 (current count)
// 2. Add 0x100000 to it and write to CNTV_TVAL_EL0 (re-arm)
// 3. Acknowledge GICv3 via ICC_EOIR1_EL1
// 4. Call timer_int_handler() and return to switch_to_user()
```

---

### 7. EL0 / User-Space Context Save & Restore

**The right aarch64 idiom for IRQ at EL0 (vector slot 16 in MINIX 3-like layout):**

```asm
el0_64_irq:
  # CPU auto-saves ELR_EL1, SPSR_EL1 on exception
  # We must save x0-x30, SP_EL0

  sub sp, sp, #16                # Make room for ELR_EL1 + SPSR_EL1 (or use TPIDR_EL1)
  stp x0, x1, [sp, #-16]!        # Save x0-x1 (push)
  stp x2, x3, [sp, #-16]!
  ... save x4-x29 ...
  stp x30, xzr, [sp, #-16]!      # Save LR (x30), align to 16 bytes

  # Save ELR_EL1 (user PC) and SPSR_EL1 (user flags)
  mrs x0, ELR_EL1
  mrs x1, SPSR_EL1
  stp x0, x1, [sp, #-16]!

  # Move to kernel stack (only needed if we switch stacks; QEMU virt allows EL1 stack)
  mov x0, sp                     # Pointer to saved regs (on EL1 stack)

  # Call Rust handler: context_stop(x0); gic_irq_handler(x0); timer_int_handler()
  bl context_stop
  bl gic_irq_handler
  bl timer_int_handler
  bl switch_to_user              # Never returns; restores saved regs and eret
```

**In `switch_to_user()` before `eret`:**

```asm
# Restore saved regs (at x0 = sp)
ldp x1, x2, [x0, #-16]!        # Restore SPSR_EL1, ELR_EL1
msr SPSR_EL1, x2
msr ELR_EL1, x1

# Restore x30-x0 (in reverse order)
ldp x30, xzr, [x0], #16
... restore x29-x4 ...
ldp x2, x3, [x0], #16
ldp x0, x1, [x0], #16

# Return to EL0
eret
```

---

### 8. Minimal Switch-to-User Flow

**MINIX 3 pattern (from x86_64, applies to aarch64):**

1. **`pick_proc()`:** Find first runnable process at highest priority.
2. **Check `RTS_NO_QUANTUM`:** If set, reset `p_cpu_time_left` and clear the flag.
3. **Check `RTS_PREEMPTED`:** If set, re-enqueue at head of priority queue (preempted process gets another chance).
4. **Process any deferred work:** Message delivery, signal handling (Slice 2.5+).
5. **Restore user context:** Copy saved registers from `proc.p_reg` into CPU registers or stack.
6. **`eret` / `iretq`:** Return to user mode.

**For Slice 2.4 with two EL0 stubs:**

```rust
fn switch_to_user() {
  loop {
    // Pick next runnable process
    let p = pick_proc();
    if p.is_none() {
      // No runnable procs; halt CPU (WFE)
      idle();
      continue;
    }

    let p = p.unwrap();

    // Reset quantum if exhausted
    if (p.rts_flags & RTS_NO_QUANTUM) != 0 {
      p.cpu_time_left = QUANTUM_TICKS;  // e.g., 100 ticks = 1 ms at 100 kHz
      p.rts_flags &= !RTS_NO_QUANTUM;
    }

    // Restore user context and eret
    restore_user_context(p);  // Never returns
  }
}
```

---

### 9. Summary: Slice 2.4 Tasks

1. **Implement run queues:**
   - `run_q_head[NR_SCHED_QUEUES]`, `run_q_tail[NR_SCHED_QUEUES]`
   - `enqueue(proc)`, `dequeue(proc)`, `pick_proc() -> Option<&Proc>`
   - `RTS_NO_QUANTUM` flag and quantum reset logic

2. **GICv3 init (aarch64):**
   - Enable GICD, GICR
   - Configure PPI 27 (virtual timer) as Group 1, priority 0x80, enabled
   - Set `ICC_PMR_EL1 = 0xFF`, `ICC_IGRPEN1_EL1 |= 1`

3. **ARM generic timer setup:**
   - `CNTV_TVAL_EL0 = tick_count` (e.g., 0x100000 for ~10 ms at 1 MHz)
   - `CNTV_CTL_EL0 = 1` (enable)
   - On each interrupt: reload `CNTV_TVAL_EL0`, acknowledge via `ICC_EOIR1_EL1`

4. **Timer interrupt handler:**
   - Decrement current process's `p_cpu_time_left`
   - If zero, set `RTS_NO_QUANTUM` and return to `switch_to_user()`
   - Acknowledge GICv3 (ICC_EOIR1_EL1)

5. **Verify with two EL0 stub tasks:**
   - Each prints a burst (e.g., "ABBB" and "CCC") to UART
   - Timer interrupts preempt them at each tick
   - Serial output shows interleaved bursts proving preemption works

