1	//! Slice-2.3 userland bootstrap: minimal TTBR0 setup + EL0 stub task.
2	//!
3	//! Builds a single 4-level page-table walk in static `.bss` storage that
4	//! maps two pages:
5	//!   - `USER_CODE_VA` → a kernel-owned page filled with the EL0 stub
6	//!     instructions (`_user_stub_start..._user_stub_end`). RO + EL0 X.
7	//!   - `USER_STACK_VA` → a kernel-owned page used as the stub's EL0 stack.
8	//!     RW + EL0, no execute.
9	//!
10	//! Populates the first free user slot in the process table (ProcNr 11 — the
11	//! slot immediately after the boot servers, currently empty) with the EL0
12	//! entry state, and returns it for `proc::sched::switch_to_user` to consume.
13	//!
14	//! Phase 3's VM server replaces all of this with proper per-process address
15	//! spaces; slice 2.4 reuses the page-table arena to add a second EL0 stub
16	//! task that exercises timer-driven preemption.
17	
18	use core::cell::UnsafeCell;
19	use core::sync::atomic::Ordering;
20	
21	use minix4_kernel_shared::ProcNr;
22	use minix4_kernel_shared::com::boot_endpoint;
23	
24	use crate::arch::aarch64::limine::kernel_va_to_pa;
25	use crate::arch::aarch64::mmu::{
26	    self, ATTR_IDX_NORMAL, PAGE_SIZE, PTE_AF, PTE_AP_RO_EL0, PTE_AP_RW_EL0, PTE_PXN,
27	    PTE_SH_INNER, PTE_UXN, PageTable, pte_attr_idx,
28	};
29	use crate::proc::Proc;
30	use crate::proc::table::proc_slot_mut;
31	
32	// ----- EL0 virtual addresses ------------------------------------------------
33	
34	/// Virtual address at which the EL0 stub's code page is mapped.
35	pub const USER_CODE_VA: u64 = 0x0040_0000; // 4 MiB
36	/// Virtual address at which the EL0 stub's stack page is mapped.
37	pub const USER_STACK_VA: u64 = 0x0080_0000; // 8 MiB
38	
39	/// First proc-table slot beyond the boot image. Boot procs occupy
40	/// `0..=INIT_PROC_NR` (i.e. `0..=10`), so `ProcNr(11)` is the first free
41	/// user slot. Slice 2.6 will replace this ad-hoc occupant with a
42	/// properly-loaded INIT.
43	const STUB_PROC_NR: ProcNr = ProcNr::new(11);
44	
45	// ----- Static storage ------------------------------------------------------
46	
47	/// 4 KiB-aligned raw byte page, used for the EL0 stub's code and stack.
48	#[repr(C, align(4096))]
49	struct UserPage(UnsafeCell<[u8; PAGE_SIZE]>);
50	// SAFETY: single-threaded boot context; no concurrent access. Same invariant
51	// documented on `ProcStorage` / `PrivStorage` in `proc::table`.
52	unsafe impl Sync for UserPage {}
53	
54	impl UserPage {
55	    const EMPTY: Self = Self(UnsafeCell::new([0; PAGE_SIZE]));
56	}
57	
58	#[repr(transparent)]
59	struct PtSlot(UnsafeCell<PageTable>);
60	// SAFETY: single-threaded boot; mutation is confined to `userland_bootstrap`.
61	unsafe impl Sync for PtSlot {}
62	
63	static L0_TABLE: PtSlot = PtSlot(UnsafeCell::new(PageTable::EMPTY));
64	static L1_TABLE: PtSlot = PtSlot(UnsafeCell::new(PageTable::EMPTY));
65	static L2_TABLE: PtSlot = PtSlot(UnsafeCell::new(PageTable::EMPTY));
66	static L3_CODE_TABLE: PtSlot = PtSlot(UnsafeCell::new(PageTable::EMPTY));
67	static L3_STACK_TABLE: PtSlot = PtSlot(UnsafeCell::new(PageTable::EMPTY));
68	
69	static USER_CODE_PAGE: UserPage = UserPage::EMPTY;
70	static USER_STACK_PAGE: UserPage = UserPage::EMPTY;
71	
72	// ----- EL0 stub blob (linked into the kernel image by `user_stub.S`) -------
73	
74	unsafe extern "C" {
75	    static _user_stub_start: u8;
76	    static _user_stub_end: u8;
77	}
78	
79	// ----- Bootstrap ----------------------------------------------------------
80	
81	/// Wire up TTBR0 mappings, copy the EL0 stub into its user page, populate
82	/// the stub's process slot, and return it.
83	///
84	/// SAFETY: must be called exactly once from `kmain` before any EL0 code
85	/// runs. Single-threaded boot context; no other reference into the static
86	/// page-table arena, user pages, or `PROC_TABLE[STUB_PROC_NR]` may exist
87	/// concurrently.
88	pub unsafe fn userland_bootstrap() -> &'static mut Proc {
89	    // 1. Verify Limine left MAIR_EL1's index 0 as Normal WB and that
90	    //    TCR_EL1's TTBR0-side fields match what `activate_user_ttbr0`
91	    //    expects. We never rewrite either register — these asserts are the
92	    //    bootstrap's only guard against a Limine config drift.
93	    mmu::assert_mair_normal_wb();
94	    mmu::assert_tcr_el1_ttbr0_ready();
95	
96	    // 2. Resolve physical addresses for our static storage. The page tables
97	    //    and the user code/stack pages all live in the kernel image (`.bss`
98	    //    section, mapped via TTBR1), so we go through Limine's kernel-
99	    //    address response rather than HHDM.
100	    let l0_pa = kernel_pa_of(L0_TABLE.0.get() as u64);
101	    let l1_pa = kernel_pa_of(L1_TABLE.0.get() as u64);
102	    let l2_pa = kernel_pa_of(L2_TABLE.0.get() as u64);
103	    let l3_code_pa = kernel_pa_of(L3_CODE_TABLE.0.get() as u64);
104	    let l3_stack_pa = kernel_pa_of(L3_STACK_TABLE.0.get() as u64);
105	    let code_page_pa = kernel_pa_of(USER_CODE_PAGE.0.get() as u64);
106	    let stack_page_pa = kernel_pa_of(USER_STACK_PAGE.0.get() as u64);
107	
108	    // 3. Build the two user mappings. The arena holds 5 tables total: L0,
109	    //    L1, L2 (shared because both VAs fall in the same 1 GiB L1 entry),
110	    //    and one L3 each (the code/stack VAs straddle different 2 MiB L2
111	    //    slots, so they need separate L3 tables).
112	    let code_attrs = PTE_AF | PTE_SH_INNER | PTE_AP_RO_EL0 | PTE_PXN | pte_attr_idx(ATTR_IDX_NORMAL);
113	    let stack_attrs = PTE_AF
114	        | PTE_SH_INNER
115	        | PTE_AP_RW_EL0
116	        | PTE_PXN
117	        | PTE_UXN
118	        | pte_attr_idx(ATTR_IDX_NORMAL);
119	
120	    // SAFETY: single-threaded boot; no other references into the table
121	    // storage exist. PAs were resolved above.
122	    unsafe {
123	        let l0 = &mut *L0_TABLE.0.get();
124	        let l1 = &mut *L1_TABLE.0.get();
125	        let l2 = &mut *L2_TABLE.0.get();
126	        let l3_code = &mut *L3_CODE_TABLE.0.get();
127	        let l3_stack = &mut *L3_STACK_TABLE.0.get();
128	
129	        mmu::map_4k(
130	            l0, l1, l2, l3_code,
131	            l1_pa, l2_pa, l3_code_pa,
132	            USER_CODE_VA, code_page_pa, code_attrs,
133	        );
134	        mmu::map_4k(
135	            l0, l1, l2, l3_stack,
136	            l1_pa, l2_pa, l3_stack_pa,
137	            USER_STACK_VA, stack_page_pa, stack_attrs,
138	        );
139	    }
140	
141	    // 4. Copy the EL0 stub into its code page (via the kernel VA), then
142	    //    clean the data side to PoU and invalidate the i-cache so the
143	    //    upcoming EL0 fetch sees the new bytes.
144	    // SAFETY: `_user_stub_*` are rodata symbols inside the kernel image;
145	    // start ≤ end is enforced by the linker output of user_stub.S.
146	    let stub_len = unsafe {
147	        (&_user_stub_end as *const u8).offset_from(&_user_stub_start as *const u8) as usize
148	    };
149	    assert!(stub_len > 0 && stub_len <= PAGE_SIZE);
150	    // SAFETY: USER_CODE_PAGE is a 4 KiB-aligned BSS page; we hold the only
151	    // mutable reference (single-threaded boot).
152	    unsafe {
153	        let dst = USER_CODE_PAGE.0.get() as *mut u8;
154	        core::ptr::copy_nonoverlapping(&_user_stub_start as *const u8, dst, stub_len);
155	        mmu::flush_icache_range(USER_CODE_PAGE.0.get() as u64, stub_len);
156	    }
157	
158	    // 5. Install TTBR0 with our L0 root. After this, USER_CODE_VA and
159	    //    USER_STACK_VA resolve to the pages we just prepared.
160	    // SAFETY: DAIF is masked from boot (Limine hands us a state with all
161	    //   four DAIF bits set). The L0 root we just built is valid.
162	    unsafe { mmu::activate_user_ttbr0(l0_pa) };
163	
164	    // 6. Populate the stub's proc slot with its EL0 entry state.
165	    // SAFETY: single-threaded boot; nobody else holds a reference into the
166	    // stub slot. Slice 2.2's `proc::init` left ProcNr 11 in the
167	    // RTS_SLOT_FREE state.
168	    let p = unsafe { proc_slot_mut(STUB_PROC_NR) }
169	        .expect("STUB_PROC_NR within proc table");
170	    populate_stub_slot(p);
171	    p
172	}
173	
174	fn populate_stub_slot(p: &mut Proc) {
175	    // Name "el0stub" + NUL fill.
176	    p.name = *b"el0stub\0\0\0\0\0\0\0\0\0";
177	    p.nr = STUB_PROC_NR;
178	    p.endpoint = boot_endpoint(STUB_PROC_NR);
179	    p.priv_id = None; // No Priv slot — trap-mask enforcement is slice 2.5.
180	    p.priority = crate::proc::table::SRV_Q;
181	    p.quantum_ms = 0;
182	    p.quantum_left = 0;
183	
184	    // EL0 entry state.
185	    p.regs.elr_el1 = USER_CODE_VA;
186	    p.regs.sp_el0 = USER_STACK_VA + PAGE_SIZE as u64;
187	    // SPSR_EL1 = 0x3C0:
188	    //   bits 9:6  (DAIF) = 1111 — keep interrupts masked until slice 2.4.
189	    //   bit  4    (M[4]) = 0    — AArch64.
190	    //   bits 3:0  (M[3:0]) = 0  — EL0t (SP = SP_EL0).
191	    p.regs.spsr_el1 = 0x3C0;
192	
193	    // Mark runnable — RTS_SLOT_FREE was set by Proc::EMPTY; clearing all
194	    // RTS bits makes the slot a live, ready process.
195	    p.rts_flags.store(0, Ordering::Relaxed);
196	}
197	
198	/// Translate a kernel-image VA to PA via Limine's kernel-address response,
199	/// panicking with a usable message if Limine didn't fill that response in.
200	fn kernel_pa_of(va: u64) -> u64 {
201	    kernel_va_to_pa(va).expect(
202	        "Limine did not populate the kernel-address response — bootloader too old?",
203	    )
204	}
