1	// Many of these constants are defined now so that the slice-2.5 IPC code and
2	// slice-2.6 kernel-call dispatch can land without churning this module
3	// again. They become live as later slices consume them.
4	#![allow(dead_code)]
5	
6	//! Kernel-internal flag bits for [`Proc`] and [`Priv`].
7	//!
8	//! [`Proc`]: super::Proc
9	//! [`Priv`]: super::Priv
10	//!
11	//! Values mirror MINIX 3 `kernel/proc.h` (RTS / MF) and `include/minix/const.h`
12	//! (PREEMPTIBLE / BILLABLE / …) so the bit semantics are recognizable. None
13	//! of these constants belong on the IPC wire — userspace never sees them —
14	//! so they live in the kernel crate rather than in `kernel-shared`.
15	//!
16	//! MINIX 4 drops a few MINIX 3 flags that are not relevant to the port:
17	//! `LU_SYS_PROC` (no live update), `MF_FLUSH_TLB` / `MF_SPROF_SEEN` (no SMP,
18	//! no profiling), `MF_SC_*` (no syscall tracing).
19	
20	use minix4_kernel_shared::ipc_const::{RECEIVE, SENDREC};
21	
22	// ---------------------------------------------------------------------------
23	// Run-time state flags (`Proc::rts_flags`).
24	//
25	// A process is runnable iff `rts_flags == 0`. Each bit identifies a distinct
26	// reason the kernel is keeping the process off the run queue; clearing all
27	// reasons makes the process runnable again.
28	// ---------------------------------------------------------------------------
29	
30	/// Process-table slot is free.
31	pub const RTS_SLOT_FREE: u32 = 0x0_0001;
32	/// Process has been explicitly stopped.
33	pub const RTS_PROC_STOP: u32 = 0x0_0002;
34	/// Blocked trying to `SEND`.
35	pub const RTS_SENDING: u32 = 0x0_0004;
36	/// Blocked trying to `RECEIVE`.
37	pub const RTS_RECEIVING: u32 = 0x0_0008;
38	/// A kernel signal has arrived for this process.
39	pub const RTS_SIGNALED: u32 = 0x0_0010;
40	/// Signal handling is in progress.
41	pub const RTS_SIG_PENDING: u32 = 0x0_0020;
42	/// Process is being traced (debugger / ptrace).
43	pub const RTS_P_STOP: u32 = 0x0_0040;
44	/// Forked system process awaiting privilege assignment.
45	pub const RTS_NO_PRIV: u32 = 0x0_0080;
46	/// Process cannot send or receive — no valid endpoint.
47	pub const RTS_NO_ENDPOINT: u32 = 0x0_0100;
48	/// Awaiting VM to set up page tables.
49	pub const RTS_VMINHIBIT: u32 = 0x0_0200;
50	/// Unhandled page fault pending.
51	pub const RTS_PAGEFAULT: u32 = 0x0_0400;
52	/// Originator of a VM memory request, waiting on resolution.
53	pub const RTS_VMREQUEST: u32 = 0x0_0800;
54	/// Target of a VM memory request, helping the originator.
55	pub const RTS_VMREQTARGET: u32 = 0x0_1000;
56	/// Preempted by a higher-priority process — re-enqueue at the front.
57	pub const RTS_PREEMPTED: u32 = 0x0_4000;
58	/// Quantum exhausted — re-enqueue at the back of the run queue.
59	pub const RTS_NO_QUANTUM: u32 = 0x0_8000;
60	/// Awaiting VM to finish boot-time setup.
61	pub const RTS_BOOTINHIBIT: u32 = 0x1_0000;
62	
63	// ---------------------------------------------------------------------------
64	// Miscellaneous flags (`Proc::misc_flags`).
65	//
66	// These do NOT block scheduling; they are status bits the kernel consults
67	// during IPC, signal delivery, and FPU handling.
68	// ---------------------------------------------------------------------------
69	
70	pub const MF_REPLY_PEND: u32 = 0x0_0001;
