1	//! Minimal PL011 UART driver for early kernel output.
2	//!
3	//! Targets the QEMU `virt` machine, where the PL011 MMIO base is fixed at
4	//! physical `0x0900_0000`. QEMU pre-initializes the controller for
5	//! 8-N-1 / 115200, so we only need to poll the TX-FIFO-full flag and write
6	//! the data register.
7	//!
8	//! Under Limine protocol revision 3 on aarch64, device memory is *not*
9	//! identity-mapped; physical addresses are reached through the Higher Half
10	//! Direct Map (HHDM). `set_base(virt)` records the post-HHDM virtual base
11	//! before any UART use. Calling `Pl011::new()` before `set_base` returns a
12	//! sink that silently drops writes -- this prevents the panic handler from
13	//! triple-faulting during very early bootstrap.
14	//!
15	//! A proper console abstraction (with locking, per-arch base discovery from
16	//! the device tree, virtio-console, etc.) arrives in Phase 6.
17	
18	use core::fmt;
19	use core::ptr::{read_volatile, write_volatile};
20	use core::sync::atomic::{AtomicUsize, Ordering};
21	
22	pub const PL011_PHYS_BASE: usize = 0x0900_0000;
23	
24	const DR_OFFSET: usize = 0x00;
25	const FR_OFFSET: usize = 0x18;
26	const FR_TXFF: u32 = 1 << 5;
27	
28	static UART_BASE: AtomicUsize = AtomicUsize::new(0);
29	
30	pub fn set_base(virt: usize) {
31	    UART_BASE.store(virt, Ordering::Release);
32	}
33	
34	pub struct Pl011 {
35	    base: usize,
36	}
37	
38	impl Pl011 {
39	    pub fn new() -> Self {
40	        Self {
41	            base: UART_BASE.load(Ordering::Acquire),
42	        }
43	    }
44	
45	    pub fn putc(&self, c: u8) {
46	        if self.base == 0 {
47	            return; // uninitialised; drop the byte
48	        }
49	        // SAFETY: `base` was set via `set_base` from a virtual address that
50	        // points at PL011 MMIO (either the identity map or HHDM_offset +
51	        // PL011_PHYS_BASE). Polling FR.TXFF before writing DR is the
52	        // documented send sequence (ARM PL011 TRM r1p5 section 3.3).
53	        unsafe {
54	            let fr = (self.base + FR_OFFSET) as *mut u32;
55	            while read_volatile(fr) & FR_TXFF != 0 {}
56	            let dr = (self.base + DR_OFFSET) as *mut u32;
57	            write_volatile(dr, c as u32);
58	        }
59	    }
60	}
61	
62	impl fmt::Write for Pl011 {
63	    fn write_str(&mut self, s: &str) -> fmt::Result {
64	        for b in s.bytes() {
65	            if b == b'\n' {
66	                self.putc(b'\r');
67	            }
68	            self.putc(b);
69	        }
70	        Ok(())
71	    }
72	}
