        let l1 = &mut *L1_TABLE.0.get();
        let l2 = &mut *L2_TABLE.0.get();
        let l3_code = &mut *L3_CODE_TABLE.0.get();
        let l3_stack = &mut *L3_STACK_TABLE.0.get();

